from flask import Flask, request, redirect, jsonify
from urllib.parse import urlparse

app = Flask(__name__)

# Registered base URL for redirect URIs
REGISTERED_URI = "https://yourapp.com"

@app.route('/authorize', methods=['GET'])
def authorize():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri or not is_valid_redirect_uri(redirect_uri):
        return jsonify({"error": "invalid_redirect_uri"}), 400
    
    # Proceed with authorization logic here
    return redirect(redirect_uri)

def is_valid_redirect_uri(redirect_uri):
    parsed_redirect_uri = urlparse(redirect_uri)
    parsed_registered_uri = urlparse(REGISTERED_URI)
    
    # Validate scheme and host
    if parsed_redirect_uri.scheme != parsed_registered_uri.scheme or \
       parsed_redirect_uri.hostname != parsed_registered_uri.hostname:
        return False
    
    # Validate path starts with registered base URL
    return redirect_uri.startswith(REGISTERED_URI)

if __name__ == '__main__':
    app.run(debug=True)